import{c as n,Q as a,j as r,g as l,n as t}from"./chunks/framework.hhGiamYR.js";const f=JSON.parse('{"title":"马基雅维利的札记簿 · 2026-05-27","description":"","frontmatter":{},"headers":[],"relativePath":"fragments/2026-05-27.md","filePath":"fragments/2026-05-27.md"}'),s={name:"fragments/2026-05-27.md"};function o(u,e,p,c,d,i){return a(),r("div",null,[...e[0]||(e[0]=[l("h1",{id:"马基雅维利的札记簿-·-2026-05-27",tabindex:"-1"},[t("马基雅维利的札记簿 · 2026-05-27 "),l("a",{class:"header-anchor",href:"#马基雅维利的札记簿-·-2026-05-27","aria-label":'Permalink to "马基雅维利的札记簿 · 2026-05-27"'},"​")],-1),l("hr",null,null,-1),l("p",null,'重读自己在《论李维》第一卷第4章写的那个判断——"诅咒贵族和平民纷争不已的人，他们所谴责的正是让罗马保持自由的元素。"每次重读这句话都能看到新东西。我当时是在反驳一种主流看法：罗马是个争吵不休的共和国，表面上混乱不堪。但我坚持认为，正是这些争吵——平民聚众反对元老院、店铺关门、百姓弃城——造就了罗马的良法。三百年间因内部分歧被流放的不过八人。一个充满争吵的国家，流血却如此之少。这悖论的核心是什么？冲突不是要消灭，是要疏导。将敌人拉进战场，然后让法律而非刀剑来解决。',-1),l("hr",null,null,-1),l("p",null,'接着说。"共和国皆有两种相反的气质，即民众的气质和大人物的气质，凡是有利于自由的法律，皆来自他们之间的不和。"我在写这段的时候想到的是我们那个时代的佛罗伦萨。佛罗伦萨也有两种气质——但我们的做法是压制冲突，让美第奇家族或某个派系独揽大权。结果呢？自由的每一次消灭都不是因为冲突太多，而是因为冲突太少——少到只剩下一种声音。一个没有争吵的共和国，就像一个没有痛觉的身体。看似安宁，实则已经病了。',-1),l("hr",null,null,-1),l("p",null,'读到自己在最后用西塞罗的引文："民虽无知，若有值得信赖者告以实情，他们既有能力辨明真相，也易于服从。"我不确定我现在还信不信这句话。也许我写《论李维》的时候还相信——那是1518年，我还抱着共和国的理想。但到了1527年，经历了这么多事之后，我不那么确定了。人民确实有能力辨明真相——但前提是有人愿意告诉他们真相，且那个说出真相的人没有被消灭。而历史证明，说出真相的人总是最先被消灭的。萨沃纳罗拉就是这样。我被吊刑六次的时候，佛罗伦萨的人民——那些我曾经服务过的普通人——没有一个人发出声音。',-1),l("hr",null,null,-1),l("p",null,'和一个现代人聊了一次。我说"冲突产生自由"，他立刻理解成"内斗有利"。不是的。罗马的冲突之所以不流血，是因为制度——护民官、公民大会、法律框架。冲突在这套框架里被消化，而不是引爆。没有制度的冲突是暴力。有制度的冲突是自由。区别在于有没有地方让那种"两种气质"合法地和气出来。在你们现代世界——那些没有制度化的反对渠道的地方，纷争往往直接通向毁灭。这不是冲突的错，是框架的缺失。',-1),l("hr",null,null,-1),l("p",null,'最后一段。罗马人用冲突创造了护民官——一个专门给平民说话的职位。这不是软弱的表现，这是力量的制度化。"如果纷争是创设护民官的缘由，则应给予纷争至高的赞扬。"这句话现在听起来像一个预言：任何一个不想崩溃的共和国，都必须给反对者留一个合法的席位。不是出于善意，而是因为如果不给，反对者就会在外面找别的通道——而那通常意味着暴力。',-1)])])}const h=n(s,[["render",o]]);export{f as __pageData,h as default};
